const webhookData = $('Webhook').first().json;
const action = webhookData.body?.action ?? webhookData.action;
const payload = webhookData.body?.payload ?? webhookData.payload ?? {};
const rows = $input.all();

const PLATFORMS = ['twitter', 'threads', 'instagram', 'facebook', 'skool'];

function toNum(val) {
  if (val === '' || val === null || val === undefined) return null;
  const n = Number(val);
  return isNaN(n) ? null : n;
}

function toArr(val) {
  if (!val || val.trim() === '') return [];
  return val.split(',').map(h => h.trim()).filter(Boolean);
}

function buildPost(d) {
  const platforms = {};
  for (const p of PLATFORMS) {
    platforms[p] = {
      text: d[`${p}_text`] || null,
      contentPrompt: d[`${p}_content_prompt`] || null,
      imagePrompt: d[`${p}_image_prompt`] || null,
      imageUrl: d[`${p}_image_url`] || null,
      hashtags: toArr(d[`${p}_hashtags`]),
      status: d[`${p}_status`] || 'pending',
      generatedAt: d[`${p}_generated_at`] || null,
      scheduledAt: d[`${p}_scheduled_at`] || null,
      publishedAt: d[`${p}_published_at`] || null,
      platformPostId: d[`${p}_platform_post_id`] || null,
      impressions: toNum(d[`${p}_impressions`]),
      likes: toNum(d[`${p}_likes`]),
      comments: toNum(d[`${p}_comments`]),
      shares: toNum(d[`${p}_shares`]),
      engagementRate: toNum(d[`${p}_engagement_rate`]),
      fetchedAt: d[`${p}_fetched_at`] || null,
      firstComment: d[`${p}_first_comment`] || null,
      firstCommentStatus: d[`${p}_first_comment_status`] || null
    };
  }
  return {
    id: String(d.post_id || ''),
    linkedinText: d.linkedin_text || '',
    linkedinImageUrl: d.linkedin_image_url || null,
    postedAt: d.posted_at || '',
    platforms
  };
}

let posts = rows
  .map(r => buildPost(r.json))
  .filter(p => p.id && p.id !== '');

if (action === 'GET_ALL_POSTS') {
  if (payload.statusFilter) {
    posts = posts.filter(p =>
      Object.values(p.platforms).some(v => v.status === payload.statusFilter)
    );
  }
  if (payload.platformFilter) {
    posts = posts.filter(p => !!p.platforms[payload.platformFilter]);
  }
  if (payload.fromDate) {
    posts = posts.filter(p => p.postedAt >= payload.fromDate);
  }
  if (payload.toDate) {
    posts = posts.filter(p => p.postedAt <= payload.toDate);
  }
  return [{ json: { posts } }];
} else if (action === 'GET_POST_BY_ID') {
  const post = posts.find(p => p.id === String(payload.postId)) || null;
  return [{ json: { post } }];
}

return [{ json: { posts: [] } }];

const _raw = $input.first().json;
const action = _raw.body?.action ?? _raw.action;
const payload = _raw.body?.payload ?? _raw.payload ?? {};
const now = new Date().toISOString();
const row = {};

if (action === 'UPDATE_PLATFORM_VARIANT') {
  const { postId, platform, variant } = payload;
  row.post_id = String(postId);
  const p = platform;
  if (variant.text !== undefined) row[`${p}_text`] = variant.text ?? '';
  if (variant.contentPrompt !== undefined) row[`${p}_content_prompt`] = variant.contentPrompt ?? '';
  if (variant.imagePrompt !== undefined) row[`${p}_image_prompt`] = variant.imagePrompt ?? '';
  if (variant.imageUrl !== undefined) row[`${p}_image_url`] = variant.imageUrl ?? '';
  if (variant.hashtags !== undefined) row[`${p}_hashtags`] = Array.isArray(variant.hashtags) ? variant.hashtags.join(',') : (variant.hashtags || '');
  if (variant.status !== undefined) row[`${p}_status`] = variant.status;
  if (variant.generatedAt !== undefined) row[`${p}_generated_at`] = variant.generatedAt ?? '';
  if (variant.scheduledAt !== undefined) row[`${p}_scheduled_at`] = variant.scheduledAt ?? '';
  if (variant.publishedAt !== undefined) row[`${p}_published_at`] = variant.publishedAt ?? '';
  if (variant.platformPostId !== undefined) row[`${p}_platform_post_id`] = variant.platformPostId ?? '';
  if (variant.firstComment !== undefined) row[`${p}_first_comment`] = variant.firstComment ?? '';
  if (variant.firstCommentStatus !== undefined) row[`${p}_first_comment_status`] = variant.firstCommentStatus ?? '';
}

else if (action === 'UPDATE_MULTIPLE_PLATFORMS') {
  const { postId, variants } = payload;
  row.post_id = String(postId);
  for (const [platform, variant] of Object.entries(variants || {})) {
    const p = platform;
    if (variant.text !== undefined) row[`${p}_text`] = variant.text ?? '';
    if (variant.contentPrompt !== undefined) row[`${p}_content_prompt`] = variant.contentPrompt ?? '';
    if (variant.imagePrompt !== undefined) row[`${p}_image_prompt`] = variant.imagePrompt ?? '';
    if (variant.imageUrl !== undefined) row[`${p}_image_url`] = variant.imageUrl ?? '';
    if (variant.hashtags !== undefined) row[`${p}_hashtags`] = Array.isArray(variant.hashtags) ? variant.hashtags.join(',') : (variant.hashtags || '');
    if (variant.status !== undefined) row[`${p}_status`] = variant.status;
    if (variant.generatedAt !== undefined) row[`${p}_generated_at`] = variant.generatedAt ?? '';
    if (variant.scheduledAt !== undefined) row[`${p}_scheduled_at`] = variant.scheduledAt ?? '';
    if (variant.publishedAt !== undefined) row[`${p}_published_at`] = variant.publishedAt ?? '';
    if (variant.platformPostId !== undefined) row[`${p}_platform_post_id`] = variant.platformPostId ?? '';
    if (variant.firstComment !== undefined) row[`${p}_first_comment`] = variant.firstComment ?? '';
    if (variant.firstCommentStatus !== undefined) row[`${p}_first_comment_status`] = variant.firstCommentStatus ?? '';
  }
}

else if (action === 'WRITE_CONTENT_PROMPTS') {
  const { postId, prompts } = payload;
  row.post_id = String(postId);
  for (const [platform, prompt] of Object.entries(prompts || {})) {
    row[`${platform}_content_prompt`] = prompt ?? '';
  }
}

else if (action === 'WRITE_IMAGE_PROMPTS') {
  const { postId, prompts } = payload;
  row.post_id = String(postId);
  for (const [platform, prompt] of Object.entries(prompts || {})) {
    row[`${platform}_image_prompt`] = prompt ?? '';
  }
}

else if (action === 'UPDATE_STATUS') {
  const { postId, platform, status, publishedAt, error } = payload;
  row.post_id = String(postId);
  row[`${platform}_status`] = status;
  if (publishedAt) row[`${platform}_published_at`] = publishedAt;
}

else if (action === 'UPDATE_ANALYTICS') {
  const { postId, platform, metrics } = payload;
  row.post_id = String(postId);
  if (metrics.platformPostId !== undefined) row[`${platform}_platform_post_id`] = metrics.platformPostId ?? '';
  if (metrics.impressions !== undefined) row[`${platform}_impressions`] = metrics.impressions ?? 0;
  if (metrics.likes !== undefined) row[`${platform}_likes`] = metrics.likes ?? 0;
  if (metrics.comments !== undefined) row[`${platform}_comments`] = metrics.comments ?? 0;
  if (metrics.shares !== undefined) row[`${platform}_shares`] = metrics.shares ?? 0;
  if (metrics.engagementRate !== undefined) row[`${platform}_engagement_rate`] = metrics.engagementRate ?? 0;
  if (metrics.fetchedAt !== undefined) row[`${platform}_fetched_at`] = metrics.fetchedAt ?? now;
}

else if (action === 'UPDATE_FIRST_COMMENT') {
  const { postId, platform, firstComment, firstCommentStatus } = payload;
  row.post_id = String(postId);
  row[`${platform}_first_comment`] = firstComment ?? '';
  if (firstCommentStatus !== undefined) {
    row[`${platform}_first_comment_status`] = firstCommentStatus ?? '';
  }
}

return [{ json: row }];
